import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.web.bind.annotation.*;

@RestController
public class ProductSearchEndpoint {
    private final JdbcTemplate jdbcTemplate;
    
    @Autowired // This means to get the bean by type, not just by name 
    public ProductSearchEndpoint(JdbcTemplate jdbcTemplate) {
        this.jdbcTemplate = jdbcTemplate;
    }  
      
    @GetMapping("/products")
    public List<Product> search(@RequestParam String productName){     
         return (List<Product>) 
             jdbcTemplate.query("SELECT * FROM Products WHERE name LIKE ?", new Object[] {"%" + productName + "%"},   // The query string and the parameters are passed to JDBC template method, which will execute it in a safe way with prepared statements if necessary (in this case we use % sign as wildcard for both sides)
             ((rs, rowNum) -> new Product(  // Converting ResultSet into Java Objects using RowMapper  
                 rs.getInt("id"),   
                 rs.getString("name")    
                  )     
              ));      
         }         
}